P4768 [NOI2018] 归程 <p>传送门</p> <p>首先题意可以转化为每次求点 $v$ 只经过点权大于 $p$ 的边能到达的所有结点中，与结点 $1$ 间最短路最小是多少。</p> <p>我们之前说过，Kruskal 是可以跑最大生成树的，且最大生成树也具有类似性质。</p> <p>那么设这样构造的 Kruskal 重构树为 $T$。根据上面的结论，容易发现 $v$ 必然存在一个祖先 $f$（可能是它自己），$a_f&gt;p,a_{father(f)}\le p$，那么 $f$ 子树内所有叶子结点就是从 $v$ 出发可达的结点，因为它们和 $v$ 的 $\operatorname{lca}$ 的点权显然均小于等于 $f$。</p> <p>那么我们可以先跑一遍以 $1$ 为起点的单源最短路，然后对每个点维护子树内叶子结点最短路最小值，最后在线倍增找到这个 $f$ 即可。复杂度 $O(m\log m+q\log m)$。</p> 参考代码 <pre><code>#include&lt;bits/stdc++.h&gt;
#define mem(a,b) memset(a,b,sizeof(a))
#define forup(i,s,e) for(i64 i=(s);i&lt;=(e);i++)
#define fordown(i,s,e) for(i64 i=(s);i&gt;=(e);i--)
using namespace std;
using i64=long long;
#define gc getchar()
inline i64 read(){
    i64 x=0,f=1;char c;
    while(!isdigit(c=gc)) if(c=='-') f=-1;
    while(isdigit(c)){x=(x&lt;&lt;3)+(x&lt;&lt;1)+(c^48);c=gc;}
    return x*f;
}
#undef gc
const i64 N=2e5+5,inf=1e18;
i64 t,n,m,q,tp,s,lans;
struct Node{
    i64 u,v,w;
}a[N&lt;&lt;1];
struct edge{
    i64 v,w;
};
vector&lt;edge&gt; e[N];
i64 fa[N],rt[N];
i64 getfa(i64 x){return x==fa[x]?x:fa[x]=getfa(fa[x]);}
struct node{
    i64 u,dis;
    bool operator &lt;(const node &amp;r)const{return dis&gt;r.dis;}
};
priority_queue&lt;node&gt; qq;
i64 vis[N],dis[N];
i64 val[N&lt;&lt;1],ans[N&lt;&lt;1],son[N&lt;&lt;1][2];
i64 f[N&lt;&lt;1][21];
void dfs(int x){
    if(x==0) return;
    forup(i,1,20){
        f[x][i]=f[f[x][i-1]][i-1];
    }
    f[son[x][0]][0]=f[son[x][1]][0]=x;
    dfs(son[x][0]);dfs(son[x][1]);
}
bool cmp(Node a,Node b){
    return a.w&gt;b.w;
}
void kruskal(){
    sort(a+1,a+m+1,cmp);
    forup(i,1,n){
        fa[i]=rt[i]=i;
        val[i]=inf;
        ans[i]=dis[i];
        son[i][0]=son[i][1]=0;
    }
    int cntn=n;
    forup(i,1,m){
        i64 u=a[i].u,v=a[i].v,w=a[i].w;
        i64 fu=getfa(u),fv=getfa(v);
        if(fu==fv) continue;
        ++cntn;
        son[cntn][0]=rt[fu];son[cntn][1]=rt[fv];
        val[cntn]=w;ans[cntn]=min(ans[son[cntn][0]],ans[son[cntn][1]]);
        fa[fu]=fv;rt[fv]=cntn;
    }
    forup(i,0,cntn){
        forup(j,0,20){
            f[i][j]=0;
        }
    }
    dfs(cntn);
}
void dijkstra(){
    while(qq.size()) qq.pop();
    forup(i,1,n){
        dis[i]=inf;vis[i]=0;
    }
    dis[1]=0;qq.push(node{1,0});
    while(qq.size()){
        i64 u=qq.top().u;qq.pop();
        if(vis[u]) continue;
        vis[u]=1;
        for(auto i:e[u]){
            i64 v=i.v,w=i.w;
            if(dis[u]+w&lt;dis[v]){
                dis[v]=dis[u]+w;
                qq.push(node{v,dis[v]});
            }
        }
    }
}
signed main(){
    t=read();
    while(t--){
        n=read();m=read();
        forup(i,1,n){
            e[i].clear();
        }
        forup(i,1,m){
            i64 u=read(),v=read(),len=read(),w=read();
            a[i].u=u;a[i].v=v;a[i].w=w;
            e[u].push_back(edge{v,len});
            e[v].push_back(edge{u,len});
        }
        dijkstra();
        kruskal();
        q=read();tp=read();s=read();lans=0;
        forup(Case,1,q){
            int x=read(),p=read();
            x=(x+tp*lans-1)%n+1;
            p=(p+tp*lans)%(s+1);
            int l=x;
            fordown(i,20,0){
                if(f[l][i]&amp;&amp;val[f[l][i]]&gt;p) l=f[l][i];
            }
            lans=ans[l];
            printf("%lld\n",ans[l]);
        }
    }
}
</code></pre> <p>容易发现上面的参考实现是从这里复制过去的。</p>

P4630 [APIO2018] 铁人两项 <p>题意就是统计所有点对 $(s,t)$，它们之间的所有简单路径点集并（不算端点）的大小之和。</p> <p>那么显然简单路径点集并的大小就是圆方树中路径上的所有点双大小之和。然后简单容斥可以得到方点点权取点双大小，圆点点权取 $-1$，然后统计树上路径点权和即可。对于统计所有点对，可以统一每个点产生了多少次贡献。这个比较简单。</p> 参考代码 <pre><code>#include&lt;bits/stdc++.h&gt;
#define mem(a,b) memset(a,b,sizeof(a))
#define forup(i,s,e) for(i64 i=(s);i&lt;=(e);i++)
#define fordown(i,s,e) for(i64 i=(s);i&gt;=(e);i--)
using namespace std;
using i64=long long;
#define gc getchar()
inline i64 read(){
    i64 x=0,f=1;char c;
    while(!isdigit(c=gc)) if(c=='-') f=-1;
    while(isdigit(c)){x=(x&lt;&lt;3)+(x&lt;&lt;1)+(c^48);c=gc;}
    return x*f;
}
#undef gc
const i64 N=2e5+5,inf=0x3f3f3f3f;
i64 n,m,w[N],ans=0;
vector&lt;i64&gt; e[N],e2[N];
i64 dfn[N],low[N],Tm,cntn;
stack&lt;i64&gt; stk;
int als;
void Tarjan(i64 x){
    dfn[x]=low[x]=++Tm;
    stk.push(x);
    ++als;
    for(auto i:e[x]){
        if(!dfn[i]){
            Tarjan(i);
            low[x]=min(low[x],low[i]);
            if(low[i]==dfn[x]){
                ++cntn;
                w[cntn]=1;
                i64 v=0;
                while(v!=i){
                    v=stk.top();stk.pop();
                    e2[v].push_back(cntn);
                    e2[cntn].push_back(v);
                    ++w[cntn];
                }
                e2[x].push_back(cntn);
                e2[cntn].push_back(x);
            }
        }else{
            low[x]=min(low[x],dfn[i]);
        }
    }
}
i64 sz[N];
void dfs2(i64 x,i64 fa){
    sz[x]=(x&lt;=n);
    for(auto i:e2[x]){
        if(i==fa) continue;
        dfs2(i,x);
        ans+=2*sz[x]*sz[i]*w[x];
        sz[x]+=sz[i];
    }
    ans+=2*sz[x]*(als-sz[x])*w[x];
}
signed main(){
    n=read();m=read();
    cntn=n;
    forup(i,1,m){
        i64 u=read(),v=read();
        e[u].push_back(v);
        e[v].push_back(u);
    }
    forup(i,1,n){
        w[i]=-1;
    }
    forup(i,1,n){
        if(!dfn[i]){
            als=0;
            Tarjan(i);
            stk.pop();
            dfs2(i,0);
        }
    }
    printf("%lld\n",ans);
}
</code></pre> CF487E Tourists <p>题意就是有两个操作，一个是修改点权，另一个是查询以 $s$ 开头 $t$ 结尾的所有简单路径上点权最小值。</p> <p>那么还是用圆方树，然后用 <code>multiset</code> 维护每个方点所有儿子的最小值，树剖维护路径上方点即可，注意特判 $\operatorname{lca}$ 的父亲。</p> <p>对于为什么只维护儿子的最小值，因为一个原点周围可能有很多个方点，如果维护整个点双的最小值复杂度会寄。</p> 参考代码 <pre><code>#include&lt;bits/stdc++.h&gt;
#define mem(a,b) memset(a,b,sizeof(a))
#define forup(i,s,e) for(register int i=(s);i&lt;=(e);i++)
#define fordown(i,s,e) for(register int i=(s);i&gt;=(e);i--)
using namespace std;
#define gc getchar()
inline int read(){
    int x=0,f=1;char c;
    while(!isdigit(c=gc)) if(c=='-') f=-1;
    while(isdigit(c)){x=(x&lt;&lt;3)+(x&lt;&lt;1)+(c^48);c=gc;}
    return x*f;
}
#undef gc
const int N=2e5+5,inf=0x3f3f3f3f;
int n,m,q,a[N],cntn;
multiset&lt;int&gt; s[N];
namespace T{
    vector&lt;int&gt; e[N];
    int dpt[N],hig[N],sz[N],son[N],fat[N],f[N];
    void dfs(int x,int fa){
        sz[x]=1;dpt[x]=dpt[fa]+1;
        fat[x]=fa;
        for(auto i:e[x]){
            if(i==fa) continue;
            dfs(i,x);
            sz[x]+=sz[i];
            if(sz[i]&gt;sz[son[x]]||son[x]==0){
                son[x]=i;
            }
        }
    }
    int st[N],ed[N],Tm,seq[N];
    void dfs(int x,int fa,int hh){
        hig[x]=hh;st[x]=++Tm;
        if(x&gt;n) s[x].insert(a[son[x]]);
        if(son[x]!=0) dfs(son[x],x,hh);
        for(auto i:e[x]){
            if(i==fa||i==son[x]) continue;
            if(x&gt;n){
                s[x].insert(a[i]);
            }
            dfs(i,x,i);
        }
        ed[x]=Tm;
        if(x&gt;n) a[x]=*s[x].begin();
        seq[st[x]]=a[x];
    }
    struct SegmentTree{
        #define mid ((l+r)&gt;&gt;1)
        #define lson l,mid,id&lt;&lt;1
        #define rson mid+1,r,id&lt;&lt;1|1
        private:
            int querymin[N&lt;&lt;2];
            void PushUp(int id){
                querymin[id]=min(querymin[id&lt;&lt;1],querymin[id&lt;&lt;1|1]);
            }
        public:
            void Build(int* A,int l=1,int r=cntn,int id=1){
                if(l==r){
                    querymin[id]=A[l];
                    return;
                }
                Build(A,lson);
                Build(A,rson);
                PushUp(id);
            }
            void Update(int P,int X,int l=1,int r=cntn,int id=1){
                if(l==r){
                    querymin[id]=X;
                    return;
                }
                if(P&lt;=mid) Update(P,X,lson);
                else       Update(P,X,rson);
                PushUp(id);
            }
            int AskMin(int L,int R,int l=1,int r=cntn,int id=1){
                if(L&lt;=l&amp;&amp;r&lt;=R){
                    return querymin[id];
                }
                int res=inf;
                if(L&lt;=mid) res=min(res,AskMin(L,R,lson));
                if(mid&lt; R) res=min(res,AskMin(L,R,rson));
                return res;
            }
    }mt; 
    void NodeUpdate(int P,int X){
        if(fat[P]){
            s[fat[P]].erase(s[fat[P]].find(a[P]));
            s[fat[P]].insert(X);
            a[fat[P]]=*s[fat[P]].begin();   
            mt.Update(st[fat[P]],a[fat[P]]);
        }
        a[P]=X;
        mt.Update(st[P],X);
    }
    int ChainAsk(int x,int y){
        if(hig[x]==hig[y]){
            if(dpt[x]&gt;dpt[y]) swap(x,y);
            int res=mt.AskMin(st[x],st[y]);
            if(x&gt;n&amp;&amp;fat[x]) res=min(res,a[fat[x]]);
            return res;
        }
        if(dpt[hig[x]]&lt;dpt[hig[y]]) swap(x,y);
        int res=inf;
        res=min(res,mt.AskMin(st[hig[x]],st[x]));
        res=min(res,ChainAsk(fat[hig[x]],y));
        return res;
    }
}
vector&lt;int&gt; e[N];
int dfn[N],low[N],dfc;
int stk[N],top;
void Tarjan(int u){
    low[u]=dfn[u]=++dfc;
    stk[++top]=u;
    for(auto v:e[u]){
        if(!dfn[v]){
            Tarjan(v);
            low[u]=min(low[u],low[v]);
            if(low[v]==dfn[u]){
                ++cntn;
                a[cntn]=inf;
                for(int x=0;x!=v;--top){
                    x=stk[top];
                    T::e[x].push_back(cntn);
                    T::e[cntn].push_back(x);
                }
                T::e[cntn].push_back(u);
                T::e[u].push_back(cntn);
            }
        }else{
            low[u]=min(low[u],dfn[v]);
        }
    }
}
signed main(){
    n=read();m=read();q=read();
    cntn=n;
    forup(i,1,n){
        a[i]=read();
    }
    forup(i,1,m){
        int u=read(),v=read();
        e[u].push_back(v);
        e[v].push_back(u);
    }
    Tarjan(1);
    T::dfs(1,0);T::dfs(1,0,1);
    T::mt.Build(T::seq);
    while(q--){
        char op;
        scanf(" %1c",&amp;op);
        if(op=='C'){
            int x=read(),w=read();
            T::NodeUpdate(x,w);
        }else{
            int u=read(),v=read();
            printf("%d\n",T::ChainAsk(u,v));
        }
    }
}
</code></pre>

CF555E Case of Computer Network <p>题意就是给边定向，使得一些点对之间存在至少一条有向路径。</p> <p>容易发现每个边双都能定向成一个强连通分量，因为任意两点间有至少两条路径。</p> <p>那么就变成了树上问题，可以树上差分维护每条边向下的路径数与向上的路径数，若两边均非零就无解。</p> <p>注意判原图连不连通。</p> 参考代码 <pre><code>#include&lt;bits/stdc++.h&gt;
#define mem(a,b) memset(a,b,sizeof(a))
#define forup(i,s,e) for(int i=(s);i&lt;=(e);i++)
#define fordown(i,s,e) for(int i=(s);i&gt;=(e);i--)
using namespace std;
#define gc getchar()
inline int read(){
    int x=0,f=1;char c;
    while(!isdigit(c=gc)) if(c=='-') f=-1;
    while(isdigit(c)){x=(x&lt;&lt;3)+(x&lt;&lt;1)+(c^48);c=gc;}
    return x*f;
}
#undef gc
const int N=2e5+5,inf=0x3f3f3f3f;
int n,m,q;
vector&lt;int&gt; e[N],e1[N];
int dfn[N],low[N],blg[N],csc,Tm,vis[N],ltk[N];
stack&lt;int&gt; stk;
void Tarjan(int x,int fa,int nw){
    low[x]=dfn[x]=++Tm;stk.push(x);
    bool flag=true;
    ltk[x]=nw;
    for(auto i:e1[x]){
        if(i==fa&amp;&amp;flag){
            flag=false;
            continue;
        }
        if(!dfn[i]){
            Tarjan(i,x,nw);
            low[x]=min(low[x],low[i]);
        }else{
            low[x]=min(low[x],dfn[i]);
        }
    }
    if(dfn[x]==low[x]){
        ++csc;
        while(stk.size()&amp;&amp;stk.top()!=x){
            blg[stk.top()]=csc;
            stk.pop();
        }
        blg[x]=csc;stk.pop();
    }
}
int dpt[N],f[N][21];
void dfs(int x,int fa){
    f[x][0]=fa;dpt[x]=dpt[fa]+1;
    forup(i,1,20){
        f[x][i]=f[f[x][i-1]][i-1];
    }
    for(auto i:e[x]){
        if(i==fa) continue;
        dfs(i,x);
    }
}
int lca(int x,int y){
    if(dpt[x]&gt;dpt[y]) swap(x,y);
    for(int i=20;i&gt;=0&amp;&amp;dpt[x]!=dpt[y];--i){
        if(dpt[f[y][i]]&gt;=dpt[x]){
            y=f[y][i];
        }
    }
    if(x==y) return x;
    for(int i=20;i&gt;=0&amp;&amp;f[x][0]!=f[y][0];--i){
        if(f[x][i]!=f[y][i]){
            x=f[x][i];y=f[y][i];
        }
    }
    return f[x][0];
}
int prea[N],preb[N];
void dfs1(int x,int fa){
    vis[x]=1;
    for(auto i:e[x]){
        if(i==fa) continue;
        dfs1(i,x);
        prea[x]+=prea[i];
        preb[x]+=preb[i];
    }
    if(prea[x]!=0&amp;&amp;preb[x]!=0){
        puts("No");
        exit(0);
    }
}
signed main(){
    n=read();m=read();q=read();
    forup(i,1,m){
        int u=read(),v=read();
        e1[u].push_back(v);e1[v].push_back(u);
    }
    forup(i,1,n){
        if(!dfn[i]){
            Tarjan(i,0,i);
        }
    }
    forup(i,1,n){
        for(auto j:e1[i]){
            if(blg[j]!=blg[i]){
                e[blg[i]].push_back(blg[j]);
            }
        }
    }
    forup(i,1,n){
        if(dpt[i]==0){
            dfs(i,0);
        }
    }
    forup(i,1,q){
        int s=read(),t=read();
        if(ltk[s]!=ltk[t]){
            puts("No");
            return 0;
        }
        if(blg[s]==blg[t]) continue;
        int Lca=lca(blg[s],blg[t]);
        prea[blg[s]]++;prea[Lca]--;
        preb[blg[t]]++;preb[Lca]--;
    }
    forup(i,1,n){
        if(!vis[i]){
            dfs1(i,0);
        }
    }
    puts("Yes");
}
</code></pre>

洛谷 P3808 【模板】AC 自动机（简单版） <pre><code>const int N=1e6+5,inf=0x3f3f3f3f;
int n;
char str[N];
struct AC_Automaton{
    int trie[N][26],cntn,cnt[N],fail[N];
    void Insert(char *a,int len){
        int p=0;
        forup(i,1,len){
            int nxt=a[i]-'a';
            if(!trie[p][nxt]) trie[p][nxt]=++cntn;
            p=trie[p][nxt];
        }
        cnt[p]++;
    }
    void Build(){
        queue&lt;int&gt; q;
        forup(i,0,25){
            if(trie[0][i]) q.push(trie[0][i]);
        }
        while(q.size()){
            int u=q.front();q.pop();
            forup(i,0,25){
                if(trie[u][i]){
                    fail[trie[u][i]]=trie[fail[u]][i];
                    q.push(trie[u][i]);
                }else{
                    trie[u][i]=trie[fail[u]][i];// (1)!
                }
            }
        }
    }
    int Ask(char *t,int len){
        int u=0,res=0;
        forup(i,1,len){
            u=trie[u][t[i]-'a'];
            for(int j=u;j&amp;&amp;cnt[j]!=-1;j=fail[j]){// (2)!
                res+=cnt[j];cnt[j]=-1;
            }
        }
        return res;
    }
}mt;
signed main(){
    n=read();
    forup(i,1,n){
        scanf(" %s",str+1);
        mt.Insert(str,strlen(str+1));
    }
    mt.Build();
    scanf(" %s",str+1);
    printf("%d\n",mt.Ask(str,strlen(str+1)));
}
</code></pre> <ol> <li>由于我们建了字典图所以这里会直接跳到存在 $i$ 这个转移的状态，如果没有会直接连向根结点。</li> <li>试跳 $u$ 的失配指针，因为它们都可能是字符串的结尾，如果 <code>cnt</code> 为 $-1$ 说明这个状态已经跳到过了，后面的也肯定都跳到过了。</li> </ol> 洛谷 P3796 【模板】AC 自动机（加强版） <p>其实几乎一样，只是建树时记一下字符串编号，最后查找字符串出现次数。</p> <p>值得一提的是这份代码复杂度不太一样，因为试跳 $fail$ 是 $O(L)$ 的，其中 $L$ 是模式串最大长度，很显然，每次跳 $fail$ 状态长度至少 $-1$。所以复杂度应是 $O(\sum|s_i|+n|\Sigma|+|S|L)$。</p> <pre><code>const int M=1e6+5,N=155,NN=2e5+5,inf=0x3f3f3f3f;
int n;
char a[N][75],str[M];
struct AC_Automaton{
    int trie[NN][26],cntn,idx[NN],fail[NN],cnt[N];
    void clear(){
        mem(trie,0);cntn=0;
        mem(idx,0);mem(fail,0);
