code <pre><code>#include&lt;bits/stdc++.h&gt;
#define int long long
using namespace std;
const int N=1e5+5;
int n,x[N],y[N];
int q,a,b;
double sx,sy;
struct Node{
    bool s,fl;//s true-&gt;竖向边; fl true-&gt;左侧/下方
    double k,b;// s true-&gt;b代表横坐标
};
Node lt[N],rt[N],upl,dwl;
int k1,k2=1;
Node ist(int a1,int b1){
    Node l;
    if(x[a1]==x[b1]){
        l.s=true;
        l.b=y[a1];
        if(sx&lt;x[a1]){
            l.fl=true;
        }else{
            l.fl=false;
        }
    }else{
        l.s=false;
        l.k=double(y[b1]-y[a1])/(x[b1]-x[a1]);//一次函数
        l.b=y[a1]-x[a1]*l.k;
        if(sy&lt;=sx*l.k+l.b){
            l.fl=true;
        }else{
            l.fl=false;
        }
    }
    return l;
}
bool pd(Node l,int a1,int b1){
    if(l.fl){
        if(l.s){
            return a1&lt;=l.b;
        }else{
            return b1&lt;=a1*l.k+l.b;
        }       
    }else{
        if(l.s){
            return a1&gt;=l.b;
        }else{
            return b1&gt;=a1*l.k+l.b;
        }       
    }
}
bool chk(int x1,int y1){
    if(pd(upl,x1,y1)&amp;&amp;pd(dwl,x1,y1)) return true;
    if(!pd(upl,x1,y1)&amp;&amp;!pd(dwl,x1,y1)) return false;
    int ll=1,rr=(n&gt;&gt;1)-1,mm,res=1;
    if(pd(upl,x1,y1)){ //二分
        while(ll&lt;=rr){
            mm=(ll+rr)&gt;&gt;1;
            if(pd(lt[mm],x1,y1)) ll=mm+1;
            else rr=mm-1;
        }
        res+=rr;
        ll=1;rr=(n&gt;&gt;1)-1;
        while(ll&lt;=rr){
            mm=(ll+rr)&gt;&gt;1;
            if(pd(rt[mm],x1,y1)) ll=mm+1;
            else rr=mm-1;
        }
        res+=rr;
        if(res&gt;(n&gt;&gt;1)) return true;
        return false;       
    }else{
        while(ll&lt;=rr){
            mm=(ll+rr)&gt;&gt;1;
            if(!pd(lt[mm],x1,y1)) ll=mm+1;
            else rr=mm-1;
        }
        res+=(n&gt;&gt;1)-ll;
        ll=1;rr=(n&gt;&gt;1)-1;
        while(ll&lt;=rr){
            mm=(ll+rr)&gt;&gt;1;
            if(!pd(rt[mm],x1,y1)) ll=mm+1;
            else rr=mm-1;
        }
        res+=(n&gt;&gt;1)-ll;
        if(res&gt;(n&gt;&gt;1)) return true;
        return false;   
    }
}
signed main(){
    scanf("%lld",&amp;n);
    for(int i=1;i&lt;=n;i++){
        scanf("%lld%lld",&amp;x[i],&amp;y[i]);
    }
    sx=(x[1]+x[(n&gt;&gt;1)+1])/2.0;sy=(y[1]+y[(n&gt;&gt;1)+1])/2.0;
    upl=ist(1,2);dwl=ist((n&gt;&gt;1)+1,(n&gt;&gt;1)+2);
    for(int i=2;i&lt;=(n&gt;&gt;1);i++){
        lt[++k1]=ist(i,i+1);
    }
    rt[1]=ist(n,1);
    for(int i=n-1;i&gt;=(n&gt;&gt;1)+2;i--){
        rt[++k2]=ist(i,i+1);
    }
    scanf("%lld",&amp;q);
    int cnt=0;
    while(q--){
        scanf("%lld%lld",&amp;a,&amp;b);
        a^=(cnt*cnt*cnt);b^=(cnt*cnt*cnt);
        if(chk(a,b)){
            puts("Yes");
            cnt++;
        }else{
            puts("No");
        }
    }
}
